function ClearLogFile()
    -- Open the file in write mode, this will create a new file or overwrite the existing one
    local file = love.filesystem.newFile("debug_log.txt", "w")
    if file then
        file:write("")  -- Writing an empty string to clear the file
        file:close()
    end
end
ClearLogFile()
function Fprint(content)
    -- Open the file in append mode
    local file = love.filesystem.newFile("debug_log.txt", "a")
    if file then
        local date = os.date("%Y-%m-%d %H:%M:%S")  -- Format: Year-Month-Day Hour:Minute:Second
        file:write(date .. " ")
        file:write(content .. "\n")
        file:close()
    end
end
